export type logoutSessionResponse200 = {
  data: ApiResponseVoid
  status: 200
}

export type logoutSessionResponseSuccess = (logoutSessionResponse200) & {
  headers: Headers;
};
;

export type logoutSessionResponse = (logoutSessionResponseSuccess)

export const getLogoutSessionUrl = (sessionId: string,
    params: LogoutSessionParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : String(value))
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/auth/sessions/${sessionId}?${stringifiedParams}` : `/api/auth/sessions/${sessionId}`
}

